// ─── Derived helpers ──────────────────────────────────────────────────────────

export const getFeatured = () => articles.filter(a => a.featured);
export const getTrending = () => articles.filter(a => a.trending);
export const getBreaking = () => articles.filter(a => a.breaking);
export const getByCategory = (cat) => articles.filter(a => a.category === cat);
export const getLatest = (n = 6) => [...articles].sort((a, b) => new Date(b.publishedAt) - new Date(a.publishedAt)).slice(0, n);
export const getMostRead = () => articles.slice(0, 5); // In production, sort by view count
export const getRelated = (article, n = 3) =>
  articles
    .filter(a => a.id !== article.id && (a.category === article.category || a.tags.some(t => article.tags.includes(t))))
    .slice(0, n);
export const searchArticles = (query) => {
  const q = query.toLowerCase();
  return articles.filter(
    a => a.title.toLowerCase().includes(q) || a.summary.toLowerCase().includes(q) || a.tags.some(t => t.toLowerCase().includes(q))
  );
};
